"""
Conversation data models for Framer.

Conversations represent AI-guided dialogue sessions that produce structured Frames.
"""
import re
from datetime import datetime, timezone
from enum import Enum
from typing import Any, Optional

import yaml
from pydantic import BaseModel, Field, field_validator


class ConversationStatus(str, Enum):
    """Status of a conversation."""
    ACTIVE = "active"
    SYNTHESIZED = "synthesized"
    ABANDONED = "abandoned"


class ConversationPurpose(str, Enum):
    """Purpose of a conversation."""
    AUTHORING = "authoring"
    REVIEW = "review"


# Regex pattern for valid conversation IDs: conv-YYYY-MM-DD-xxxxxx
CONVERSATION_ID_PATTERN = re.compile(r"^conv-\d{4}-\d{2}-\d{2}-[a-zA-Z0-9]+$")


class ConversationMessage(BaseModel):
    """A single message in a conversation."""
    id: str
    role: str = Field(description="user or assistant")
    content: str
    timestamp: datetime = Field(default_factory=lambda: datetime.now(timezone.utc))
    metadata: Optional[dict[str, Any]] = None
    sender_name: Optional[str] = None


class ConversationState(BaseModel):
    """Tracks what the AI has learned from the conversation so far."""
    frame_type: Optional[str] = None
    sections_covered: dict[str, float] = Field(
        default_factory=lambda: {
            "problem_statement": 0.0,
            "root_cause": 0.0,
            "user_perspective": 0.0,
            "engineering_framing": 0.0,
            "validation_thinking": 0.0,
        }
    )
    extracted_content: dict[str, str] = Field(default_factory=dict)
    gaps: list[str] = Field(default_factory=list)
    ready_to_synthesize: bool = False


class ConversationMeta(BaseModel):
    """Metadata for a conversation (stored in meta.yaml)."""
    id: str
    frame_id: Optional[str] = None
    project_id: Optional[str] = None
    owner: str
    purpose: ConversationPurpose = ConversationPurpose.AUTHORING
    status: ConversationStatus = ConversationStatus.ACTIVE
    created_at: datetime = Field(default_factory=lambda: datetime.now(timezone.utc))
    updated_at: datetime = Field(default_factory=lambda: datetime.now(timezone.utc))

    @field_validator("id")
    @classmethod
    def validate_conversation_id(cls, v: str) -> str:
        if not CONVERSATION_ID_PATTERN.match(v):
            raise ValueError(
                f"Conversation ID must match pattern 'conv-YYYY-MM-DD-xxxxxx', got: {v}"
            )
        return v

    def to_yaml(self) -> str:
        data = {
            "id": self.id,
            "owner": self.owner,
            "purpose": self.purpose.value,
            "status": self.status.value,
            "created_at": self.created_at.isoformat(),
            "updated_at": self.updated_at.isoformat(),
        }
        if self.frame_id:
            data["frame_id"] = self.frame_id
        if self.project_id:
            data["project_id"] = self.project_id
        return yaml.dump(data, default_flow_style=False, sort_keys=False)

    @classmethod
    def from_yaml(cls, yaml_str: str) -> "ConversationMeta":
        data = yaml.safe_load(yaml_str)
        purpose_str = data.get("purpose", "authoring")
        return cls(
            id=data["id"],
            owner=data["owner"],
            purpose=ConversationPurpose(purpose_str),
            status=ConversationStatus(data["status"]),
            frame_id=data.get("frame_id"),
            project_id=data.get("project_id"),
            created_at=datetime.fromisoformat(data["created_at"].replace("Z", "+00:00"))
                if isinstance(data["created_at"], str) else data["created_at"],
            updated_at=datetime.fromisoformat(data["updated_at"].replace("Z", "+00:00"))
                if isinstance(data["updated_at"], str) else data["updated_at"],
        )


class Conversation(BaseModel):
    """Complete conversation combining metadata, messages, and state."""
    meta: ConversationMeta
    messages: list[ConversationMessage] = Field(default_factory=list)
    state: ConversationState = Field(default_factory=ConversationState)

    @property
    def id(self) -> str:
        return self.meta.id

    @property
    def status(self) -> ConversationStatus:
        return self.meta.status

    @property
    def owner(self) -> str:
        return self.meta.owner

"""
Conversation Service for file-based conversation operations.

Follows the same pattern as FrameService: one directory per conversation.
Storage: /data/conversations/conv-{id}/ with meta.yaml + messages.json + state.json
"""
import json
import shutil
import uuid
from datetime import datetime, timezone
from pathlib import Path
from typing import Optional

from app.models.conversation import (
    Conversation,
    ConversationMeta,
    ConversationMessage,
    ConversationPurpose,
    ConversationState,
    ConversationStatus,
)


class ConversationNotFoundError(Exception):
    pass


class ConversationService:
    """Service for managing conversations via file system."""

    def __init__(self, data_path: Path):
        self.data_path = Path(data_path)
        self.conversations_path = self.data_path / "conversations"

    def _generate_id(self) -> str:
        date_str = datetime.now(timezone.utc).strftime("%Y-%m-%d")
        unique_suffix = uuid.uuid4().hex[:6]
        return f"conv-{date_str}-{unique_suffix}"

    def _get_conv_dir(self, conv_id: str) -> Path:
        return self.conversations_path / conv_id

    def _read_messages(self, conv_dir: Path) -> list[ConversationMessage]:
        messages_file = conv_dir / "messages.json"
        if not messages_file.exists():
            return []
        data = json.loads(messages_file.read_text())
        return [
            ConversationMessage(
                id=m["id"],
                role=m["role"],
                content=m["content"],
                timestamp=datetime.fromisoformat(m["timestamp"]) if "timestamp" in m else datetime.now(timezone.utc),
                metadata=m.get("metadata"),
                sender_name=m.get("sender_name"),
            )
            for m in data.get("messages", [])
        ]

    def _write_messages(self, conv_dir: Path, messages: list[ConversationMessage]) -> None:
        messages_file = conv_dir / "messages.json"
        data = {
            "messages": [
                {
                    "id": m.id,
                    "role": m.role,
                    "content": m.content,
                    "timestamp": m.timestamp.isoformat(),
                    "metadata": m.metadata,
                    "sender_name": m.sender_name,
                }
                for m in messages
            ]
        }
        messages_file.write_text(json.dumps(data, indent=2))

    def _read_state(self, conv_dir: Path) -> ConversationState:
        state_file = conv_dir / "state.json"
        if not state_file.exists():
            return ConversationState()
        data = json.loads(state_file.read_text())
        return ConversationState(**data)

    def _write_state(self, conv_dir: Path, state: ConversationState) -> None:
        state_file = conv_dir / "state.json"
        state_file.write_text(json.dumps(state.model_dump(), indent=2))

    def create_conversation(
        self,
        owner: str,
        purpose: Optional[ConversationPurpose] = None,
        frame_id: Optional[str] = None,
        project_id: Optional[str] = None,
    ) -> Conversation:
        conv_id = self._generate_id()
        conv_dir = self._get_conv_dir(conv_id)
        conv_dir.mkdir(parents=True, exist_ok=True)

        meta = ConversationMeta(
            id=conv_id,
            owner=owner,
            purpose=purpose or ConversationPurpose.AUTHORING,
            frame_id=frame_id,
            project_id=project_id,
        )
        state = ConversationState()

        (conv_dir / "meta.yaml").write_text(meta.to_yaml())
        self._write_messages(conv_dir, [])
        self._write_state(conv_dir, state)

        return Conversation(meta=meta, messages=[], state=state)

    def get_conversation(self, conv_id: str) -> Conversation:
        conv_dir = self._get_conv_dir(conv_id)
        if not conv_dir.exists():
            raise ConversationNotFoundError(f"Conversation not found: {conv_id}")

        meta = ConversationMeta.from_yaml((conv_dir / "meta.yaml").read_text())
        messages = self._read_messages(conv_dir)
        state = self._read_state(conv_dir)

        return Conversation(meta=meta, messages=messages, state=state)

    def list_conversations(
        self,
        owner: Optional[str] = None,
        status: Optional[ConversationStatus] = None,
        frame_id: Optional[str] = None,
        project_id: Optional[str] = None,
    ) -> list[Conversation]:
        conversations = []
        if not self.conversations_path.exists():
            return conversations

        for conv_dir in self.conversations_path.iterdir():
            if conv_dir.is_dir() and conv_dir.name.startswith("conv-"):
                try:
                    conv = self.get_conversation(conv_dir.name)
                    if owner and conv.owner != owner:
                        continue
                    if status and conv.status != status:
                        continue
                    if frame_id and conv.meta.frame_id != frame_id:
                        continue
                    if project_id is not None and conv.meta.project_id != project_id:
                        continue
                    conversations.append(conv)
                except Exception:
                    pass

        return conversations

    def add_message(
        self, conv_id: str, role: str, content: str, metadata: Optional[dict] = None,
        sender_name: Optional[str] = None,
    ) -> ConversationMessage:
        conv_dir = self._get_conv_dir(conv_id)
        if not conv_dir.exists():
            raise ConversationNotFoundError(f"Conversation not found: {conv_id}")

        messages = self._read_messages(conv_dir)
        msg_id = f"msg-{len(messages) + 1:03d}"
        message = ConversationMessage(
            id=msg_id, role=role, content=content, metadata=metadata,
            sender_name=sender_name,
        )
        messages.append(message)
        self._write_messages(conv_dir, messages)

        # Update timestamp
        meta = ConversationMeta.from_yaml((conv_dir / "meta.yaml").read_text())
        meta.updated_at = datetime.now(timezone.utc)
        (conv_dir / "meta.yaml").write_text(meta.to_yaml())

        return message

    def update_state(self, conv_id: str, state: ConversationState) -> Conversation:
        conv_dir = self._get_conv_dir(conv_id)
        if not conv_dir.exists():
            raise ConversationNotFoundError(f"Conversation not found: {conv_id}")

        self._write_state(conv_dir, state)

        meta = ConversationMeta.from_yaml((conv_dir / "meta.yaml").read_text())
        meta.updated_at = datetime.now(timezone.utc)
        (conv_dir / "meta.yaml").write_text(meta.to_yaml())

        messages = self._read_messages(conv_dir)
        return Conversation(meta=meta, messages=messages, state=state)

    def link_frame(self, conv_id: str, frame_id: str) -> Conversation:
        conv_dir = self._get_conv_dir(conv_id)
        if not conv_dir.exists():
            raise ConversationNotFoundError(f"Conversation not found: {conv_id}")

        meta = ConversationMeta.from_yaml((conv_dir / "meta.yaml").read_text())
        meta.frame_id = frame_id
        meta.updated_at = datetime.now(timezone.utc)
        (conv_dir / "meta.yaml").write_text(meta.to_yaml())

        messages = self._read_messages(conv_dir)
        state = self._read_state(conv_dir)
        return Conversation(meta=meta, messages=messages, state=state)

    def update_status(self, conv_id: str, status: ConversationStatus) -> Conversation:
        conv_dir = self._get_conv_dir(conv_id)
        if not conv_dir.exists():
            raise ConversationNotFoundError(f"Conversation not found: {conv_id}")

        meta = ConversationMeta.from_yaml((conv_dir / "meta.yaml").read_text())
        meta.status = status
        meta.updated_at = datetime.now(timezone.utc)
        (conv_dir / "meta.yaml").write_text(meta.to_yaml())

        messages = self._read_messages(conv_dir)
        state = self._read_state(conv_dir)
        return Conversation(meta=meta, messages=messages, state=state)

    def delete_conversation(self, conv_id: str) -> None:
        conv_dir = self._get_conv_dir(conv_id)
        if not conv_dir.exists():
            raise ConversationNotFoundError(f"Conversation not found: {conv_id}")
        shutil.rmtree(conv_dir)

"""
Frames API endpoints.
"""
from typing import Optional

from fastapi import APIRouter, Depends, HTTPException, Request, status
from pydantic import BaseModel, Field

import logging

from app.models.frame import Frame, FrameContent, FrameStatus, FrameType, Comment
from app.services.frame_service import FrameService, FrameNotFoundError
from app.services.git_service import GitService
from app.auth.pocketbase import get_current_user, User

logger = logging.getLogger(__name__)


# Request/Response models
class CreateFrameRequest(BaseModel):
    """Request body for creating a frame."""
    type: FrameType
    owner: str
    content: Optional[dict] = None
    project_id: Optional[str] = None


class UpdateFrameRequest(BaseModel):
    """Request body for updating a frame."""
    content: dict


class UpdateStatusRequest(BaseModel):
    """Request body for updating frame status."""
    status: FrameStatus


class UpdateMetaRequest(BaseModel):
    """Request body for updating frame metadata."""
    reviewer: Optional[str] = None
    approver: Optional[str] = None


class SubmitFeedbackRequest(BaseModel):
    """Request body for submitting implementation feedback."""
    outcome: str  # success | partial | failed
    summary: str
    lessons_learned: list[str] = Field(default_factory=list)


class CreateCommentRequest(BaseModel):
    """Request body for creating a comment."""
    section: str
    author: str
    content: str


class FrameResponse(BaseModel):
    """Response model for a frame."""
    id: str
    type: str
    status: str
    owner: str
    content: dict
    meta: dict

    @classmethod
    def from_frame(cls, frame: Frame) -> "FrameResponse":
        return cls(
            id=frame.id,
            type=frame.type.value,
            status=frame.status.value,
            owner=frame.owner,
            content={
                "problem_statement": frame.content.problem_statement,
                "root_cause": frame.content.root_cause,
                "user_perspective": frame.content.user_perspective,
                "engineering_framing": frame.content.engineering_framing,
                "validation_thinking": frame.content.validation_thinking,
            },
            meta={
                "created_at": frame.meta.created_at.isoformat(),
                "updated_at": frame.meta.updated_at.isoformat(),
                "project_id": frame.meta.project_id,
                "ai_score": frame.meta.ai_score,
                "ai_breakdown": frame.meta.ai_breakdown,
                "ai_feedback": frame.meta.ai_feedback,
                "ai_issues": frame.meta.ai_issues,
                "reviewer": frame.meta.reviewer,
                "approver": frame.meta.approver,
                "review_summary": frame.meta.review_summary,
                "review_comments": frame.meta.review_comments,
                "review_recommendation": frame.meta.review_recommendation,
            }
        )


class FrameListItem(BaseModel):
    """Response model for frame list item."""
    id: str
    type: str
    status: str
    owner: str
    project_id: Optional[str] = None
    reviewer: Optional[str] = None
    approver: Optional[str] = None
    updated_at: str


class CommentResponse(BaseModel):
    """Response model for a comment."""
    id: str
    section: str
    author: str
    content: str
    created_at: str


class FrameHistoryEntry(BaseModel):
    """Response model for a frame history entry."""
    hash: str
    message: str
    author_name: str
    timestamp: str
    diff: Optional[str] = None


def get_frame_service(request: Request) -> FrameService:
    """Dependency to get the frame service from app state."""
    return request.app.state.frame_service


def get_git_service(request: Request) -> GitService:
    """Dependency to get the git service from app state."""
    return request.app.state.git_service


def _git_commit(git_service: GitService, frame_id: str, message: str, author_name: str = "Framer", author_email: str = "framer@system") -> None:
    """Auto-commit frame changes. Non-blocking, errors are logged."""
    try:
        git_service.commit_frame_changes(
            frame_id=frame_id,
            message=message,
            author_name=author_name,
            author_email=author_email,
        )
    except Exception as e:
        logger.warning("Git commit failed for frame %s: %s", frame_id, e)


def create_frames_router(require_auth: bool = False) -> APIRouter:
    """Create the frames API router.

    Args:
        require_auth: If True, all mutating endpoints require authentication.
    """
    router = APIRouter()

    # Build dependencies list based on auth requirement
    def get_auth_dependencies():
        if require_auth:
            return [Depends(get_current_user)]
        return []

    @router.post("", status_code=status.HTTP_201_CREATED, dependencies=get_auth_dependencies())
    def create_frame(
        request: CreateFrameRequest,
        frame_service: FrameService = Depends(get_frame_service),
        git_service: GitService = Depends(get_git_service),
    ) -> FrameResponse:
        """Create a new frame."""
        content = None
        if request.content:
            content = FrameContent(**request.content)

        frame = frame_service.create_frame(
            frame_type=request.type,
            owner=request.owner,
            content=content,
            project_id=request.project_id,
        )

        _git_commit(git_service, frame.id, f"Create {request.type.value} frame")

        return FrameResponse.from_frame(frame)

    @router.get("/{frame_id}")
    def get_frame(
        frame_id: str,
        frame_service: FrameService = Depends(get_frame_service),
    ) -> FrameResponse:
        """Get a frame by ID."""
        try:
            frame = frame_service.get_frame(frame_id)
            return FrameResponse.from_frame(frame)
        except FrameNotFoundError:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail=f"Frame not found: {frame_id}",
            )

    @router.get("")
    def list_frames(
        status: Optional[str] = None,
        owner: Optional[str] = None,
        project_id: Optional[str] = None,
        frame_service: FrameService = Depends(get_frame_service),
    ) -> list[FrameListItem]:
        """List all frames with optional filters."""
        frames = frame_service.list_frames(project_id=project_id)

        # Apply filters
        if status:
            frames = [f for f in frames if f.status.value == status]
        if owner:
            frames = [f for f in frames if f.owner == owner]

        return [
            FrameListItem(
                id=f.id,
                type=f.type.value,
                status=f.status.value,
                owner=f.owner,
                project_id=f.meta.project_id,
                reviewer=f.meta.reviewer,
                approver=f.meta.approver,
                updated_at=f.meta.updated_at.isoformat(),
            )
            for f in frames
        ]

    @router.put("/{frame_id}", dependencies=get_auth_dependencies())
    def update_frame(
        frame_id: str,
        request: UpdateFrameRequest,
        frame_service: FrameService = Depends(get_frame_service),
        git_service: GitService = Depends(get_git_service),
    ) -> FrameResponse:
        """Update a frame's content."""
        try:
            content = FrameContent(**request.content)
            frame = frame_service.update_frame_content(frame_id, content)
            _git_commit(git_service, frame_id, "Update frame content")
            return FrameResponse.from_frame(frame)
        except FrameNotFoundError:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail=f"Frame not found: {frame_id}",
            )

    @router.patch("/{frame_id}/status", dependencies=get_auth_dependencies())
    def update_status(
        frame_id: str,
        request: UpdateStatusRequest,
        frame_service: FrameService = Depends(get_frame_service),
        git_service: GitService = Depends(get_git_service),
    ) -> FrameResponse:
        """Update a frame's status."""
        try:
            frame = frame_service.update_frame_status(frame_id, request.status)
            _git_commit(git_service, frame_id, f"Status → {request.status.value}")
            return FrameResponse.from_frame(frame)
        except FrameNotFoundError:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail=f"Frame not found: {frame_id}",
            )
        except ValueError as e:
            raise HTTPException(
                status_code=status.HTTP_400_BAD_REQUEST,
                detail=str(e),
            )

    @router.patch("/{frame_id}/meta", dependencies=get_auth_dependencies())
    def update_meta(
        frame_id: str,
        request: UpdateMetaRequest,
        frame_service: FrameService = Depends(get_frame_service),
        git_service: GitService = Depends(get_git_service),
    ) -> FrameResponse:
        """Update frame metadata (reviewer, approver)."""
        try:
            frame = frame_service.update_frame_meta(
                frame_id,
                reviewer=request.reviewer,
                approver=request.approver,
            )
            _git_commit(git_service, frame_id, "Update frame metadata")
            return FrameResponse.from_frame(frame)
        except FrameNotFoundError:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail=f"Frame not found: {frame_id}",
            )

    @router.post("/{frame_id}/feedback", dependencies=get_auth_dependencies())
    def submit_feedback(
        frame_id: str,
        request: SubmitFeedbackRequest,
        frame_service: FrameService = Depends(get_frame_service),
        git_service: GitService = Depends(get_git_service),
    ) -> FrameResponse:
        """Submit implementation feedback and archive the frame."""
        try:
            frame_service.add_feedback(
                frame_id=frame_id,
                went_well=request.summary if request.outcome == "success" else "",
                could_improve=request.summary if request.outcome != "success" else "",
                lessons_learned="\n".join(f"- {l}" for l in request.lessons_learned) if request.lessons_learned else "",
            )
            frame = frame_service.update_frame_status(frame_id, FrameStatus.ARCHIVED)
            _git_commit(git_service, frame_id, f"Feedback: {request.outcome}")
            return FrameResponse.from_frame(frame)
        except FrameNotFoundError:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail=f"Frame not found: {frame_id}",
            )

    @router.delete("/{frame_id}", status_code=status.HTTP_204_NO_CONTENT, dependencies=get_auth_dependencies())
    def delete_frame(
        frame_id: str,
        frame_service: FrameService = Depends(get_frame_service),
    ):
        """Delete a frame."""
        try:
            frame_service.delete_frame(frame_id)
        except FrameNotFoundError:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail=f"Frame not found: {frame_id}",
            )

    @router.post("/{frame_id}/comments", status_code=status.HTTP_201_CREATED, dependencies=get_auth_dependencies())
    def add_comment(
        frame_id: str,
        request: CreateCommentRequest,
        frame_service: FrameService = Depends(get_frame_service),
    ) -> CommentResponse:
        """Add a comment to a frame."""
        try:
            comment = frame_service.add_comment(
                frame_id=frame_id,
                section=request.section,
                author=request.author,
                content=request.content,
            )
            return CommentResponse(
                id=comment.id,
                section=comment.section,
                author=comment.author,
                content=comment.content,
                created_at=comment.created_at.isoformat(),
            )
        except FrameNotFoundError:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail=f"Frame not found: {frame_id}",
            )

    @router.get("/{frame_id}/comments")
    def get_comments(
        frame_id: str,
        frame_service: FrameService = Depends(get_frame_service),
    ) -> list[CommentResponse]:
        """Get all comments for a frame."""
        try:
            comments = frame_service.get_comments(frame_id)
            return [
                CommentResponse(
                    id=c.id,
                    section=c.section,
                    author=c.author,
                    content=c.content,
                    created_at=c.created_at.isoformat(),
                )
                for c in comments
            ]
        except FrameNotFoundError:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail=f"Frame not found: {frame_id}",
            )

    @router.get("/{frame_id}/history")
    def get_frame_history(
        frame_id: str,
        limit: int = 20,
        include_diff: bool = True,
        frame_service: FrameService = Depends(get_frame_service),
        git_service: GitService = Depends(get_git_service),
    ) -> list[FrameHistoryEntry]:
        """Get version history for a frame."""
        # Verify frame exists
        try:
            frame_service.get_frame(frame_id)
        except FrameNotFoundError:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail=f"Frame not found: {frame_id}",
            )

        history = git_service.get_frame_history(frame_id, limit=limit)
        return [
            FrameHistoryEntry(
                hash=entry["hash"],
                message=entry["message"],
                author_name=entry["author_name"],
                timestamp=entry["timestamp"].isoformat(),
                diff=git_service.get_commit_diff(entry["hash"]) if include_diff else None,
            )
            for entry in history
        ]

    return router

