210→/**
211→ * Framer API Client class
212→ */
213→export class FramerAPIClient {
214→  private baseURL: string;
215→  private token: string | null = null;
216→
217→  constructor(baseURL: string = API_BASE_URL) {
218→    this.baseURL = baseURL;
219→  }
220→
221→  /**
222→   * Set authentication token
223→   */
224→  setToken(token: string | null) {
225→    this.token = token;
226→  }
227→
228→  /**
229→   * Get current token
230→   */
231→  getToken(): string | null {
232→    return this.token;
233→  }
234→
235→  /**
236→   * Make an API request
237→   */
238→  private async request<T>(endpoint: string, options: RequestOptions = {}): Promise<T> {
239→    const { method = 'GET', body, headers = {}, signal } = options;
240→
241→    const controller = new AbortController();
242→    const timeoutId = setTimeout(() => controller.abort(), API_TIMEOUT);
243→
244→    try {
245→      const requestHeaders: Record<string, string> = {
246→        'Content-Type': 'application/json',
247→        ...headers,
248→      };
249→
250→      if (this.token) {
251→        requestHeaders['Authorization'] = `Bearer ${this.token}`;
252→      }
253→
254→      const response = await fetch(`${this.baseURL}${endpoint}`, {
255→        method,
256→        headers: requestHeaders,
257→        body: body ? JSON.stringify(body) : undefined,
258→        signal: signal || controller.signal,
259→      });
260→
261→      clearTimeout(timeoutId);
262→
263→      if (!response.ok) {
264→        let detail: string | undefined;
265→        try {
266→          const errorData = await response.json();
267→          detail = errorData.detail;
268→        } catch {
269→          // Ignore JSON parse errors
270→        }
271→        throw new APIError(
272→          `API request failed: ${response.statusText}`,
273→          response.status,
274→          detail
275→        );
276→      }
277→
278→      // Handle 204 No Content
279→      if (response.status === 204) {
280→        return undefined as T;
281→      }
282→
283→      return await response.json();
284→    } catch (error) {
285→      clearTimeout(timeoutId);
286→      if (error instanceof APIError) {
287→        throw error;
288→      }
289→      if (error instanceof Error && error.name === 'AbortError') {
290→        throw new APIError('Request timeout', 408);
291→      }
292→      throw new APIError('Network error', 0, String(error));
293→    }
294→  }
295→
296→  // ==================== Frame Endpoints ====================
297→
298→  /**
299→   * List all frames with optional filters
300→   */
301→  async listFrames(filters?: { status?: string; owner?: string; project_id?: string }): Promise<FrameListItem[]> {
302→    const params = new URLSearchParams();
303→    if (filters?.status) params.append('status', filters.status);
304→    if (filters?.owner) params.append('owner', filters.owner);
305→    if (filters?.project_id) params.append('project_id', filters.project_id);
306→
307→    const query = params.toString();
308→    return this.request<FrameListItem[]>(`/api/frames${query ? `?${query}` : ''}`);
309→  }
310→
311→  /**
312→   * Get a single frame by ID
313→   */
314→  async getFrame(id: string): Promise<FrameResponse> {
315→    return this.request<FrameResponse>(`/api/frames/${id}`);
316→  }
317→
318→  /**
319→   * Create a new frame
320→   */
321→  async createFrame(data: {
322→    type: FrameType;
323→    owner: string;
324→    project_id?: string;
325→    content?: {
326→      problem_statement?: string;
327→      root_cause?: string;
328→      user_perspective?: string;
329→      engineering_framing?: string;
330→      validation_thinking?: string;
331→    };
332→  }): Promise<FrameResponse> {
333→    return this.request<FrameResponse>('/api/frames', {
334→      method: 'POST',
335→      body: data,
336→    });
337→  }
338→
339→  /**
340→   * Update frame content
341→   */
342→  async updateFrame(id: string, content: {
343→    problem_statement?: string;
344→    root_cause?: string;
345→    user_perspective?: string;
346→    engineering_framing?: string;
347→    validation_thinking?: string;
348→  }): Promise<FrameResponse> {
349→    return this.request<FrameResponse>(`/api/frames/${id}`, {
350→      method: 'PUT',
351→      body: { content },
352→    });
353→  }
354→
355→  /**
356→   * Update frame status
357→   */
358→  async updateFrameStatus(id: string, status: FrameStatus): Promise<FrameResponse> {
359→    return this.request<FrameResponse>(`/api/frames/${id}/status`, {
360→      method: 'PATCH',
361→      body: { status },
362→    });
363→  }
364→
365→  /**
366→   * Delete a frame
367→   */
368→  async deleteFrame(id: string): Promise<void> {
369→    return this.request<void>(`/api/frames/${id}`, {
370→      method: 'DELETE',
371→    });
372→  }
373→
374→  // ==================== Feedback Endpoint ====================
375→
376→  /**
377→   * Submit implementation feedback for a frame
378→   */
379→  async submitFeedback(frameId: string, data: {
380→    outcome: string;
