382→    lessons_learned: string[];
383→  }): Promise<FrameResponse> {
384→    return this.request<FrameResponse>(`/api/frames/${frameId}/feedback`, {
385→      method: 'POST',
386→      body: data,
387→    });
388→  }
389→
390→  // ==================== User Endpoints ====================
391→
392→  /**
393→   * List users from PocketBase
394→   */
395→  async listUsers(): Promise<Array<{ id: string; name: string; email: string }>> {
396→    return this.request<Array<{ id: string; name: string; email: string }>>('/api/users');
397→  }
398→
399→  /**
