401→   */
402→  async updateFrameMeta(frameId: string, data: {
403→    reviewer?: string;
404→    approver?: string;
405→  }): Promise<FrameResponse> {
406→    return this.request<FrameResponse>(`/api/frames/${frameId}/meta`, {
407→      method: 'PATCH',
408→      body: data,
409→    });
410→  }
411→
412→  // ==================== Comment Endpoints ====================
413→
414→  /**
