  1→import { create } from 'zustand';
  2→import {
  3→  Conversation,
  4→  ConversationMessage,
  5→  ConversationPurpose,
  6→  ConversationState,
  7→  ConversationListItem,
  8→  KnowledgeSearchResult,
  9→} from '@/types';
 10→import { getAPIClient } from '@/lib/api';
 11→import { useProjectStore } from './projectStore';
 12→import { useFrameStore } from './index';
 13→
 14→interface ConversationStore {
 15→  // Data
 16→  activeConversation: Conversation | null;
 17→  conversations: ConversationListItem[];
 18→  relevantKnowledge: Array<Record<string, unknown>>;
 19→
 20→  // UI State
 21→  isTyping: boolean;
 22→  isLoading: boolean;
 23→  isPreviewing: boolean;
 24→  previewContent: Record<string, string> | null;
 25→  previewMessageCount: number;
 26→  error: string | null;
 27→
 28→  // Actions
 29→  startConversation: (owner: string, purpose?: ConversationPurpose, frameId?: string) => Promise<Conversation>;
 30→  sendMessage: (content: string, senderName?: string) => Promise<void>;
 31→  retryMessage: (messageId: string) => Promise<void>;
 32→  previewFrame: () => Promise<void>;
 33→  clearPreview: () => void;
 34→  synthesizeFrame: () => Promise<string | null>;
 35→  summarizeReview: () => Promise<string | null>;
 36→  loadConversation: (id: string) => Promise<void>;
 37→  loadConversations: (owner?: string) => Promise<void>;
 38→  clearConversation: () => void;
 39→  setError: (error: string | null) => void;
 40→}
 41→
 42→function transformConversationResponse(response: any): Conversation {
 43→  return {
 44→    id: response.id,
 45→    owner: response.owner,
 46→    status: response.status,
 47→    purpose: response.purpose || 'authoring',
 48→    frameId: response.frame_id,
 49→    projectId: response.project_id,
 50→    messages: response.messages.map((m: any) => ({
 51→      id: m.id,
 52→      role: m.role,
 53→      content: m.content,
 54→      timestamp: m.timestamp,
 55→      metadata: m.metadata,
 56→      senderName: m.sender_name,
 57→    })),
 58→    state: {
 59→      frameType: response.state.frame_type,
 60→      sectionsCovered: {
 61→        problemStatement: response.state.sections_covered?.problem_statement ?? 0,
 62→        rootCause: response.state.sections_covered?.root_cause ?? 0,
 63→        userPerspective: response.state.sections_covered?.user_perspective ?? 0,
 64→        engineeringFraming: response.state.sections_covered?.engineering_framing ?? 0,
 65→        validationThinking: response.state.sections_covered?.validation_thinking ?? 0,
 66→      },
 67→      gaps: response.state.gaps || [],
 68→      readyToSynthesize: response.state.ready_to_synthesize || false,
 69→    },
 70→    createdAt: response.created_at,
 71→    updatedAt: response.updated_at,
 72→  };
 73→}
 74→
 75→function transformStateResponse(state: any): ConversationState {
 76→  return {
 77→    frameType: state.frame_type,
 78→    sectionsCovered: {
 79→      problemStatement: state.sections_covered?.problem_statement ?? 0,
 80→      rootCause: state.sections_covered?.root_cause ?? 0,
 81→      userPerspective: state.sections_covered?.user_perspective ?? 0,
 82→      engineeringFraming: state.sections_covered?.engineering_framing ?? 0,
 83→      validationThinking: state.sections_covered?.validation_thinking ?? 0,
 84→    },
 85→    gaps: state.gaps || [],
 86→    readyToSynthesize: state.ready_to_synthesize || false,
 87→  };
 88→}
 89→
 90→export const useConversationStore = create<ConversationStore>()((set, get) => ({
 91→  activeConversation: null,
 92→  conversations: [],
 93→  relevantKnowledge: [],
 94→  isTyping: false,
 95→  isLoading: false,
 96→  isPreviewing: false,
 97→  previewContent: null,
 98→  previewMessageCount: 0,
 99→  error: null,
100→
101→  setError: (error) => set({ error }),
102→
103→  startConversation: async (owner, purpose?, frameId?) => {
104→    set({ isLoading: true, error: null });
105→    try {
106→      const api = getAPIClient();
107→      const projectId = useProjectStore.getState().currentProjectId;
108→      const response = await api.startConversation(owner, purpose, frameId, projectId ?? undefined);
109→      const conv = transformConversationResponse(response);
110→      set({ activeConversation: conv, isLoading: false, relevantKnowledge: [] });
111→      return conv;
112→    } catch (err) {
113→      set({
114→        error: err instanceof Error ? err.message : 'Failed to start conversation',
115→        isLoading: false,
116→      });
117→      throw err;
118→    }
119→  },
120→
121→  sendMessage: async (content, senderName?) => {
122→    const { activeConversation } = get();
123→    if (!activeConversation) return;
124→
125→    const wasSynthesized = activeConversation.status === 'synthesized';
126→
127→    // Optimistically add user message and reactivate if synthesized
128→    const userMsg: ConversationMessage = {
129→      id: `temp-${Date.now()}`,
130→      role: 'user',
131→      content,
132→      timestamp: new Date().toISOString(),
133→      senderName,
134→    };
135→
136→    set((s) => ({
137→      activeConversation: s.activeConversation
138→        ? {
139→            ...s.activeConversation,
140→            status: wasSynthesized ? 'active' : s.activeConversation.status,
141→            messages: [...s.activeConversation.messages, userMsg],
142→          }
143→        : null,
144→      isTyping: true,
145→      error: null,
146→      // Invalidate preview cache since conversation changed
147→      previewContent: null,
148→      previewMessageCount: 0,
149→    }));
150→
151→    try {
152→      const api = getAPIClient();
153→      const contentLanguage = useFrameStore.getState().contentLanguage;
154→      const response = await api.sendConversationMessage(
155→        activeConversation.id,
156→        content,
157→        senderName,
158→        contentLanguage !== 'en' ? contentLanguage : undefined
159→      );
160→
161→      const aiMsg: ConversationMessage = {
162→        id: response.ai_response.id,
163→        role: 'assistant',
164→        content: response.ai_response.content,
165→        timestamp: response.ai_response.timestamp,
166→        metadata: response.ai_response.metadata,
167→      };
168→
169→      const updatedState = transformStateResponse(response.state);
170→
171→      set((s) => ({
172→        activeConversation: s.activeConversation
173→          ? {
174→              ...s.activeConversation,
175→              messages: [
176→                // Replace temp user msg with real one, add AI response
177→                ...s.activeConversation.messages.filter(
178→                  (m) => m.id !== userMsg.id
179→                ),
180→                {
181→                  id: response.message.id,
182→                  role: 'user',
183→                  content: response.message.content,
184→                  timestamp: response.message.timestamp,
185→                  metadata: response.message.metadata,
186→                  senderName: response.message.sender_name,
187→                },
188→                aiMsg,
189→              ],
190→              state: updatedState,
191→            }
192→          : null,
193→        relevantKnowledge: response.relevant_knowledge || [],
194→        isTyping: false,
195→      }));
196→    } catch (err) {
197→      // Mark the user message as failed so the user can retry
198→      set((s) => ({
199→        activeConversation: s.activeConversation
200→          ? {
201→              ...s.activeConversation,
202→              messages: s.activeConversation.messages.map((m) =>
203→                m.id === userMsg.id ? { ...m, status: 'failed' as const } : m
204→              ),
205→            }
206→          : null,
207→        error: err instanceof Error ? err.message : 'Failed to send message',
208→        isTyping: false,
209→      }));
210→    }
211→  },
212→
213→  retryMessage: async (messageId) => {
214→    const { activeConversation } = get();
215→    if (!activeConversation) return;
216→
217→    const failedMsg = activeConversation.messages.find(
218→      (m) => m.id === messageId && m.status === 'failed'
219→    );
220→    if (!failedMsg) return;
221→
222→    // Remove the failed message and re-send
223→    set((s) => ({
224→      activeConversation: s.activeConversation
225→        ? {
226→            ...s.activeConversation,
227→            messages: s.activeConversation.messages.filter((m) => m.id !== messageId),
228→          }
229→        : null,
230→      error: null,
231→    }));
232→
233→    // Re-send through the normal sendMessage path
234→    await get().sendMessage(failedMsg.content, failedMsg.senderName);
235→  },
236→
237→  previewFrame: async () => {
238→    const { activeConversation, previewContent, previewMessageCount } = get();
239→    if (!activeConversation) return;
240→
241→    const currentMsgCount = activeConversation.messages.length;
242→
243→    // Reuse cached preview if no new messages since last preview
244→    if (previewContent && previewMessageCount === currentMsgCount) {
245→      return; // Modal will show from existing previewContent
246→    }
247→
248→    set({ isPreviewing: true, error: null });
249→    try {
250→      const api = getAPIClient();
251→      const response = await api.previewFrame(activeConversation.id);
252→      set({
253→        previewContent: response.content,
254→        previewMessageCount: currentMsgCount,
255→        isPreviewing: false,
256→      });
257→    } catch (err) {
258→      set({
259→        error: err instanceof Error ? err.message : 'Failed to preview frame',
260→        isPreviewing: false,
261→      });
262→    }
263→  },
264→
265→  clearPreview: () => set({ previewContent: null }),
266→
267→  synthesizeFrame: async () => {
268→    const { activeConversation, previewContent, previewMessageCount } = get();
269→    if (!activeConversation) return null;
270→
271→    // Reuse cached preview content if still fresh (no new messages since preview)
272→    const currentMsgCount = activeConversation.messages.length;
273→    const cachedContent =
274→      previewContent && previewMessageCount === currentMsgCount
275→        ? previewContent
276→        : undefined;
277→
278→    set({ isLoading: true, error: null });
279→    try {
280→      const api = getAPIClient();
281→      const response = await api.synthesizeFrame(activeConversation.id, cachedContent);
282→
283→      set((s) => ({
284→        activeConversation: s.activeConversation
285→          ? {
286→              ...s.activeConversation,
287→              status: 'synthesized',
288→              frameId: response.frame_id,
289→            }
290→          : null,
291→        isLoading: false,
292→        previewContent: null,
293→        previewMessageCount: 0,
294→      }));
295→
296→      return response.frame_id;
297→    } catch (err) {
298→      set({
299→        error: err instanceof Error ? err.message : 'Failed to synthesize frame',
300→        isLoading: false,
301→      });
302→      return null;
303→    }
304→  },
305→
306→  summarizeReview: async () => {
307→    const { activeConversation } = get();
308→    if (!activeConversation) return null;
309→
310→    set({ isLoading: true, error: null });
311→    try {
