  43→function formatHistoryTimestamp(ts: string): string {
  44→  const date = new Date(ts);
  45→  const now = new Date();
  46→  const diffMs = now.getTime() - date.getTime();
  47→  const diffMin = Math.floor(diffMs / 60000);
  48→  if (diffMin < 1) return 'just now';
  49→  if (diffMin < 60) return `${diffMin}m ago`;
  50→  const diffHrs = Math.floor(diffMin / 60);
  51→  if (diffHrs < 24) return `${diffHrs}h ago`;
  52→  const diffDays = Math.floor(diffHrs / 24);
  53→  if (diffDays < 7) return `${diffDays}d ago`;
  54→  return date.toLocaleDateString();
  55→}
