  1→import { create } from 'zustand';
  2→import { persist } from 'zustand/middleware';
  3→import { Frame, FrameSection, AIConfig, FrameType, FrameStatus, ReviewComment, FrameFeedback, AppSpace } from '@/types';
  4→import { getAPIClient, transformFrameResponse, transformFrameToContent, transformAIEvaluation } from '@/lib/api';
  5→import { useProjectStore } from './projectStore';
  6→
  7→interface FrameStore {
  8→  // Data
  9→  frames: Frame[];
 10→
 11→  // UI State
 12→  selectedFrameId: string | null;
 13→  focusedSection: FrameSection | null;
 14→  currentSpace: AppSpace;
 15→  contentLanguage: 'en' | 'zh';
 16→
 17→  // Loading & Error State
 18→  isLoading: boolean;
 19→  error: string | null;
 20→
 21→  // Track unsaved frames (frames created but not explicitly saved)
 22→  unsavedFrameIds: Set<string>;
 23→
 24→  // AI Config
 25→  aiConfig: AIConfig | null;
 26→
 27→  // Actions
 28→  setSelectedFrame: (id: string | null) => void;
 29→  setFocusedSection: (section: FrameSection | null) => void;
 30→  setCurrentSpace: (space: AppSpace) => void;
 31→  setContentLanguage: (lang: 'en' | 'zh') => void;
 32→  setAIConfig: (config: AIConfig | null) => void;
 33→  setError: (error: string | null) => void;
 34→
 35→  // Frame CRUD
 36→  createFrame: (type: FrameType, ownerId: string) => Promise<Frame>;
 37→  updateFrame: (id: string, updates: Partial<Frame>) => Promise<void>;
 38→  deleteFrame: (id: string) => Promise<void>;
 39→  saveFrame: (id: string) => Promise<void>;
 40→  discardUnsavedFrame: (id: string) => void;
 41→  isFrameSaved: (id: string) => boolean;
 42→  loadFrames: () => Promise<void>;
 43→
 44→  // Frame Status
 45→  changeStatus: (id: string, status: FrameStatus) => Promise<void>;
 46→  submitForReview: (id: string, reviewerId?: string) => Promise<void>;
 47→  markAsReady: (id: string) => Promise<void>;
 48→  startFeedback: (id: string) => Promise<void>;
 49→  submitFeedback: (id: string, feedback: FrameFeedback) => Promise<void>;
 50→
 51→  // AI Operations
 52→  evaluateFrame: (id: string) => Promise<void>;
 53→
 54→  // Comments
 55→  addComment: (frameId: string, section: FrameSection, content: string, authorId: string) => Promise<void>;
 56→
 57→  // Get helpers
 58→  getFrame: (id: string) => Frame | undefined;
 59→  getFramesByStatus: (status: FrameStatus) => Frame[];
 60→  getWorkingFrames: () => Frame[];
 61→  getArchivedFrames: () => Frame[];
 62→}
 63→
 64→export const useFrameStore = create<FrameStore>()(
 65→  persist(
 66→    (set, get) => ({
 67→      // Initial data - empty, will be loaded from API
 68→      frames: [],
 69→
 70→      // UI State
 71→      selectedFrameId: null,
 72→      focusedSection: null,
 73→      currentSpace: 'working',
 74→      contentLanguage: 'en',
 75→
 76→      // Loading & Error State
 77→      isLoading: false,
 78→      error: null,
 79→
 80→      // Track unsaved frames
 81→      unsavedFrameIds: new Set(),
 82→
 83→      // AI Config
 84→      aiConfig: null,
 85→
 86→      // Actions
 87→      setSelectedFrame: (id) => set({ selectedFrameId: id }),
 88→      setFocusedSection: (section) => set({ focusedSection: section }),
 89→      setCurrentSpace: (space) => set({ currentSpace: space, selectedFrameId: null }),
 90→      setContentLanguage: (lang) => set({ contentLanguage: lang }),
 91→      setAIConfig: (config) => set({ aiConfig: config }),
 92→      setError: (error) => set({ error }),
 93→
 94→      // Load frames from API
 95→      loadFrames: async () => {
 96→        set({ isLoading: true, error: null });
 97→        try {
 98→          const api = getAPIClient();
 99→          const projectId = useProjectStore.getState().currentProjectId;
100→          const frameList = await api.listFrames(
101→            projectId ? { project_id: projectId } : undefined
102→          );
103→
104→          // Load full details for each frame
105→          const frames: Frame[] = [];
106→          for (const item of frameList) {
107→            try {
108→              const response = await api.getFrame(item.id);
109→              frames.push(transformFrameResponse(response));
110→            } catch {
111→              // Skip frames that fail to load
112→              console.warn(`Failed to load frame ${item.id}`);
113→            }
114→          }
115→
116→          set({ frames, isLoading: false });
117→        } catch (err) {
118→          set({
119→            error: err instanceof Error ? err.message : 'Failed to load frames',
120→            isLoading: false,
121→          });
122→        }
123→      },
124→
125→      // Frame CRUD
126→      createFrame: async (type, ownerId) => {
127→        set({ isLoading: true, error: null });
