  1→/**
  2→ * API Response Transformers
  3→ *
  4→ * Convert between backend (snake_case) and frontend (camelCase) formats.
  5→ */
  6→
  7→import type { Frame, FrameType, FrameStatus } from '@/types';
  8→import type { FrameResponse, FrameListItem, AIEvaluateResponse } from './client';
  9→
 10→/**
 11→ * Normalize content that may be a JSON-stringified object into readable markdown.
 12→ * Handles legacy frames where structured objects were stored as JSON strings.
 13→ */
 14→function normalizeContent(content: string): string {
 15→  if (!content || content.trim() === '') return '';
 16→
 17→  // Try to detect if it's a JSON object string
 18→  const trimmed = content.trim();
 19→  if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
 20→    try {
 21→      const parsed = JSON.parse(trimmed);
 22→      if (typeof parsed === 'object' && parsed !== null) {
 23→        return flattenObjectToMarkdown(parsed);
 24→      }
 25→    } catch {
 26→      // Not valid JSON, return as-is
 27→    }
 28→  }
 29→
 30→  return content;
 31→}
 32→
 33→/**
 34→ * Convert a legacy structured object into readable markdown text.
 35→ */
 36→function flattenObjectToMarkdown(obj: Record<string, unknown>): string {
 37→  const lines: string[] = [];
 38→
 39→  for (const [key, value] of Object.entries(obj)) {
 40→    // Convert camelCase key to readable label
 41→    const label = key
 42→      .replace(/([A-Z])/g, ' $1')
 43→      .replace(/^./, (s) => s.toUpperCase())
 44→      .trim();
 45→
 46→    if (Array.isArray(value)) {
 47→      if (value.length > 0) {
 48→        lines.push(`**${label}:**`);
 49→        for (const item of value) {
 50→          lines.push(`- ${String(item)}`);
 51→        }
 52→        lines.push('');
 53→      }
 54→    } else if (typeof value === 'string' && value.trim()) {
 55→      lines.push(`**${label}:** ${value}`);
 56→      lines.push('');
 57→    } else if (typeof value === 'boolean') {
 58→      // skip booleans (confirmation fields)
 59→    }
 60→  }
 61→
 62→  return lines.join('\n').trim();
 63→}
 64→
 65→/**
 66→ * Transform backend FrameResponse to frontend Frame
 67→ */
 68→export function transformFrameResponse(response: FrameResponse): Frame {
 69→  return {
 70→    id: response.id,
 71→    type: response.type as FrameType,
 72→    status: response.status as FrameStatus,
 73→    projectId: response.meta.project_id ?? undefined,
 74→    problemStatement: response.content.problem_statement || '',
 75→    rootCause: normalizeContent(response.content.root_cause || ''),
 76→    userPerspective: normalizeContent(response.content.user_perspective),
 77→    engineeringFraming: normalizeContent(response.content.engineering_framing),
 78→    validationThinking: normalizeContent(response.content.validation_thinking),
 79→    ownerId: response.owner,
 80→    createdAt: new Date(response.meta.created_at),
 81→    updatedAt: new Date(response.meta.updated_at),
 82→    reviewer: response.meta.reviewer ?? undefined,
 83→    approver: response.meta.approver ?? undefined,
 84→    aiScore: response.meta.ai_score ?? undefined,
 85→    aiScoreBreakdown: response.meta.ai_breakdown ?? undefined,
 86→    aiFeedback: response.meta.ai_feedback ?? undefined,
 87→    aiIssues: response.meta.ai_issues ?? undefined,
 88→    reviewSummary: response.meta.review_summary ?? undefined,
 89→    reviewComments: response.meta.review_comments ?? undefined,
 90→    reviewRecommendation: response.meta.review_recommendation ?? undefined,
 91→  };
 92→}
