 95→  isLoading: false,
 96→  isPreviewing: false,
 97→  previewContent: null,
 98→  previewMessageCount: 0,
 99→  error: null,
100→
101→  setError: (error) => set({ error }),
102→
103→  startConversation: async (owner, purpose?, frameId?) => {
104→    set({ isLoading: true, error: null });
105→    try {
106→      const api = getAPIClient();
107→      const projectId = useProjectStore.getState().currentProjectId;
108→      const response = await api.startConversation(owner, purpose, frameId, projectId ?? undefined);
109→      const conv = transformConversationResponse(response);
