function buildDocument(frame: Frame, lang: 'en' | 'zh'): string {
  const parts: string[] = [];

  const ps = pickLang(frame.problemStatement, frame.problemStatementEn, frame.problemStatementZh, lang);
  if (ps.trim()) {
