file.content:
version: '3.8'

# Base configuration - Use with environment-specific overrides
# Usage: docker-compose --env-file config/.env.dev up -d
#        docker-compose --env-file config/.env.prod up -d

services:
  # PocketBase - Authentication & Database
  pocketbase:
    image: ${POCKETBASE_IMAGE:-ghcr.io/muchobien/pocketbase:latest}
    container_name: ${POCKETBASE_CONTAINER_NAME:-framer-pocketbase}
    restart: ${RESTART_POLICY:-unless-stopped}
    ports:
      - "${POCKETBASE_PORT:-8090}:8090"
    volumes:
      - pocketbase_data:/pb_data
      - ./pocketbase/pb_migrations:/pb_migrations
    environment:
      - ADMIN_EMAIL=${POCKETBASE_ADMIN_EMAIL:-}
      - ADMIN_PASSWORD=${POCKETBASE_ADMIN_PASSWORD:-}
    healthcheck:
      test: ["CMD", "wget", "--no-verbose", "--tries=1", "--spider", "http://localhost:8090/api/health"]
      interval: ${HEALTHCHECK_INTERVAL:-10s}
      timeout: ${HEALTHCHECK_TIMEOUT:-5s}
      retries: ${HEALTHCHECK_RETRIES:-5}

  # FastAPI Backend
  backend:
    build:
      context: .
      dockerfile: Dockerfile.backend
    container_name: ${BACKEND_CONTAINER_NAME:-framer-backend}
    restart: ${RESTART_POLICY:-unless-stopped}
    ports:
      - "${BACKEND_PORT:-8000}:8000"
    environment:
      - POCKETBASE_URL=${POCKETBASE_INTERNAL_URL:-http://pocketbase:8090}
      - DATA_PATH=${BACKEND_DATA_PATH:-/data}
      - LOG_LEVEL=${BACKEND_LOG_LEVEL:-info}
      - CORS_ORIGINS=${BACKEND_CORS_ORIGINS:-http://localhost:3000}
      - DEBUG=${DEBUG:-false}
      # AI Configuration
      - AI_CONFIG_PATH=/data/ai.yaml
      - AI_PROVIDER=${AI_PROVIDER:-}
      - AI_MODEL=${AI_MODEL:-}
      - AI_API_KEY=${AI_API_KEY:-}
      - AI_ENDPOINT=${AI_ENDPOINT:-}
      - AI_TEMPERATURE=${AI_TEMPERATURE:-}
      - AI_MAX_TOKENS=${AI_MAX_TOKENS:-}
      - AI_TIMEOUT=${AI_TIMEOUT:-}
      - AI_SSL_VERIFY=${AI_SSL_VERIFY:-}
    volumes:
      - backend_data:/data
      - ./config:/config:ro
      - ./data/templates:/data/templates:ro
    depends_on:
      pocketbase:
        condition: service_healthy
    healthcheck:
      test: ["CMD", "python", "-c", "import urllib.request; urllib.request.urlopen('http://localhost:8000/docs')"]
      interval: ${HEALTHCHECK_INTERVAL:-10s}
      timeout: ${HEALTHCHECK_TIMEOUT:-5s}
      retries: ${HEALTHCHECK_RETRIES:-5}

  # Next.js Frontend
  frontend:
    build:
      context: .
      dockerfile: Dockerfile.frontend
      args:
        - NEXT_PUBLIC_API_BASE_URL=${NEXT_PUBLIC_API_BASE_URL:-http://localhost:8000}
        - NEXT_PUBLIC_POCKETBASE_URL=${NEXT_PUBLIC_POCKETBASE_URL:-http://localhost:8090}
    container_name: ${FRONTEND_CONTAINER_NAME:-framer-frontend}
    restart: ${RESTART_POLICY:-unless-stopped}
    ports:
      - "${FRONTEND_PORT:-3000}:3000"
    environment:
      - NEXT_PUBLIC_API_BASE_URL=${NEXT_PUBLIC_API_BASE_URL:-http://localhost:8000}
      - NEXT_PUBLIC_POCKETBASE_URL=${NEXT_PUBLIC_POCKETBASE_URL:-http://localhost:8090}
      - NEXT_PUBLIC_API_TIMEOUT=${NEXT_PUBLIC_API_TIMEOUT:-30000}
      - NODE_ENV=${NODE_ENV:-production}
    depends_on:
      - backend

volumes:
  pocketbase_data:
  backend_data:

# Framer Project Makefile
# Common commands for development and deployment

.PHONY: help install dev test test-backend test-e2e build docker-build docker-up docker-down clean

# Default target
help:
	@echo "Framer Project Commands"
	@echo ""
	@echo "Development:"
	@echo "  make install      - Install all dependencies"
	@echo "  make dev          - Start development servers (backend + frontend)"
	@echo "  make dev-backend  - Start backend server only"
	@echo "  make dev-frontend - Start frontend server only"
	@echo ""
	@echo "Testing:"
	@echo "  make test         - Run all tests"
	@echo "  make test-backend - Run backend tests only"
	@echo "  make test-e2e     - Run E2E tests"
	@echo "  make test-e2e-ui  - Run E2E tests with UI"
	@echo ""
	@echo "Building:"
	@echo "  make build        - Build frontend for production"
	@echo ""
	@echo "Docker:"
	@echo "  make docker-build - Build Docker images"
	@echo "  make docker-up    - Start all services"
	@echo "  make docker-down  - Stop all services"
	@echo "  make docker-dev   - Start development environment"
	@echo ""
	@echo "Cleanup:"
	@echo "  make clean        - Remove build artifacts"

# Install dependencies
install:
	@echo "Installing backend dependencies..."
	cd src/backend && pip install -r requirements.txt
	@echo "Installing frontend dependencies..."
	cd prototype && npm install
	@echo "Installing Playwright browsers..."
	cd prototype && npx playwright install

# Development
dev: dev-backend dev-frontend

dev-backend:
	@echo "Starting backend server..."
	cd src/backend && uvicorn app.main:get_app --reload --port 8000

dev-frontend:
	@echo "Starting frontend server..."
	cd prototype && npm run dev

# Testing
test: test-backend test-e2e

test-backend:
	@echo "Running backend tests..."
	python -m pytest tests/backend/ -v

test-e2e:
	@echo "Running E2E tests..."
	cd prototype && npm run test:e2e

test-e2e-ui:
	@echo "Running E2E tests with UI..."
	cd prototype && npm run test:e2e:ui

# Building
build:
	@echo "Building frontend..."
	cd prototype && npm run build

# Docker commands
docker-build:
	@echo "Building Docker images..."
	docker-compose build

docker-up:
	@echo "Starting all services..."
	docker-compose up -d
	@echo ""
	@echo "Services started:"
	@echo "  Frontend: http://localhost:3000"
	@echo "  Backend:  http://localhost:8000"
	@echo "  PocketBase: http://localhost:8090/_/"

docker-down:
	@echo "Stopping all services..."
	docker-compose down

docker-dev:
	@echo "Starting development environment..."
	docker-compose -f docker-compose.dev.yml up

docker-logs:
	docker-compose logs -f

# Cleanup
clean:
	@echo "Cleaning build artifacts..."
	rm -rf prototype/.next
	rm -rf prototype/node_modules/.cache
	rm -rf __pycache__
	find . -type d -name "__pycache__" -exec rm -rf {} + 2>/dev/null || true
	find . -type f -name "*.pyc" -delete 2>/dev/null || true
	@echo "Clean complete"
